body.script:
// Proxy (Scramjet)
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('https://cdn.jsdelivr.net/gh/PeteZah-G/PeteStatic@main/sw.js');
}

let tabs = [], current = 0;

function renderTabs() {
  const c = document.getElementById('tabBar');
  c.innerHTML = '';
  tabs.forEach((t, i) => {
    const el = document.createElement('div');
    el.className = `tab ${i === current ? 'active' : ''}`;
    el.innerHTML = `${t.title} <span onclick="event.stopImmediatePropagation();closeTab(${i});" style="margin-left:10px;color:#999;">×</span>`;
    el.onclick = () => switchTab(i);
    c.appendChild(el);
  });
}

function addTab(url) {
  if (!url.startsWith('http')) url = 'https://' + url;
  const title = new URL(url).hostname.replace('www.', '');
  tabs.push({url, title});
  current = tabs.length - 1;
  loadCurrent();
}

function switchTab(i) {
  current = i;
  loadCurrent();
}

function loadCurrent() {
  if (tabs.length === 0) return;
  document.getElementById('mainFrame').src = tabs[current].url;
  renderTabs();
}

function closeTab(i) {
  if (tabs.length <= 1) return;
  tabs.splice(i, 1);
  if (current >= tabs.length) current = tabs.length - 1;
  loadCurrent();
}

function goUrl() {
  const v = document.getElementById('urlInput').value.trim();
  if (v) addTab(v);
}

function customize() {
  const n = prompt('New name?', document.title);
  if (n) document.title = n;
}

function panic() {
  document.body.style.display = 'none';
  setTimeout(() => document.body.style.display = 'flex', 1200);
}

let esc = 0;
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    esc++;
    if (esc >= 2) {
      document.body.style.display = 'none';
      setTimeout(() => { if (confirm('Return to NexusForge?')) document.body.style.display = 'flex'; }, 800);
      esc = 0;
    }
  }
});

window.onload = () => addTab('https://google.com');
